module RefModule(
    input               clk,
    input               rst,
    input               up_down,

    output reg [2:0]    count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        count <= 3'b000;
    else begin
        if (up_down)
            count <= count + 1;
        else
            count <= count - 1;
    end
end

endmodule
